import java.io.*;import java.util.*;class Main{static int solve(int[][]m,int k){int R=m.length,C=m[0].length,best=Integer.MIN_VALUE;for(int top=0;top<R;top++){int[]s=new int[C];for(int bot=top;bot<R;bot++){for(int c=0;c<C;c++)s[c]+=m[bot][c];TreeSet<Integer>pre=new TreeSet<>();pre.add(0);int cur=0;for(int x:s){cur+=x;Integer p=pre.ceiling(cur-k);if(p!=null)best=Math.max(best,cur-p);pre.add(cur);}}}return best;}public static void main(String[]a)throws Exception{String[]d=new String(System.in.readAllBytes()).trim().split("\\s+");if(d.length==1&&d[0].isEmpty())return;int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int r=Integer.parseInt(d[idx++]),c=Integer.parseInt(d[idx++]);int[][]m=new int[r][c];for(int i=0;i<r;i++)for(int j=0;j<c;j++)m[i][j]=Integer.parseInt(d[idx++]);int k=Integer.parseInt(d[idx++]);if(tc>0)out.append("\n\n");out.append(solve(m,k));}System.out.print(out);}}
